import type React from 'react';

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '../utils/cn';
import { Box } from './Box';

const frameVariants = cva('rounded border p-3', {
  variants: {
    color: {
      default: 'border bg-card',
      muted: 'border-muted bg-card',
      danger: 'border-card-danger-border bg-card-danger',
    },
  },
  defaultVariants: {
    color: 'default',
  },
});

/**
 * A simple presentational component for framing content, with different color
 * options.
 */
function Frame({
  className,
  children,
  color,
  ...props
}: React.ComponentProps<typeof Box> & VariantProps<typeof frameVariants>) {
  return (
    <Box className={cn(frameVariants({ color }), className)} {...props}>
      {children}
    </Box>
  );
}

export { Frame };
